### 3. **GENERATOR HANDLER - RPC Communication**
**Location:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775491965006-gcblk5/packages/generator-helper/src/generatorHandler.ts`

The `generatorHandler` is the bridge between a generator process and the CLI. It uses JSON-RPC over stdin/stderr:

```typescript
export interface Handler {
  onGenerate(options: GeneratorOptions): Promise<any>
  onManifest?(config: GeneratorConfig): GeneratorManifest | Promise<GeneratorManifest>
}

export function generatorHandler(handler: Handler): void {
  const stdinInterface = readline.createInterface({
    input: process.stdin,
    crlfDelay: Infinity,
  })

  stdinInterface.on('line', async (line: string) => {
    const json = JSON.parse(line)

    // Two methods: 'generate' and 'getManifest'
    if (json.method === 'generate' && json.params) {
      try {
        const result = await handler.onGenerate(json.params)
        respond({
          jsonrpc: '2.0',
          result: result,
          id: json.id,
        })
      } catch (_e) {
        // Error response
        respond({
          jsonrpc: '2.0',
          error: {
            code: -32000,
            message: e.message,
            data: { stack: e.stack },
          },
          id: json.id,
        })
      }
    }

    if (json.method === 'getManifest') {
      // Similar pattern for manifest
    }
  })

  process.stdin.resume()
}

function respond(response: JsonRpc.Response): void {
  process.stderr.write(JSON.stringify(response) + '\n')
}
```

