The `getGenerators()` function orchestrates the entire generator lifecycle:

```typescript
export type GeneratorRegistry = Record<string, GeneratorRegistryEntry>

export type GeneratorRegistryEntry =
  | { type: 'rpc'; generatorPath: string; isNode?: boolean }
  | { type: 'in-process'; generator: IGenerator }

export async function getGenerators(options: GetGeneratorOptions): Promise<Generator[]> {
  // 1. Load schema and parse generator blocks
  const schemaContext = await loadSchemaContext({ schemaPath })

  // 2. Get DMMF from engine
  const dmmf = await getDMMF({
    datamodel: schemaContext.schemaFiles,
    previewFeatures: extractPreviewFeatures(schemaContext.generators),
  })

  // 3. Create generator instances (InProcessGenerator or JsonRpcGenerator)
  const generators = await pMap(
    generatorConfigs,
    async (generatorConfig, index) => {
      const providerValue = parseEnvValue(generatorConfig.provider)
      const generatorDefinition = registry[providerValue] ?? {
        type: 'rpc',
        generatorPath: providerValue,
      }

      const generatorInstance = match(generatorDefinition)
        .with({ type: 'in-process' }, ({ generator }) => 
          new InProcessGenerator(generatorConfig, generator))
        .with({ type: 'rpc' }, ({ generatorPath, isNode }) => 
          new JsonRpcGenerator(generatorPath, generatorConfig, isNode))
        .exhaustive()

      await generatorInstance.init() // Get manifest
      generatorInstance.setOptions(options)
      return generatorInstance
    },
  )

  // 4. Check generator dependencies
  for (const g of generators) {
    if (g.manifest?.requiresGenerators) {
      for (const neededGenerator of g.manifest.requiresGenerators) {
        if (!generatorProviders.includes(neededGenerator)) {
          throw new Error(`Missing required generator: ${neededGenerator}`)
        }
      }
    }
  }

  // 5. Download binaries if needed
  const binaryPathsByVersion = await getBinaryPathsByVersion({ ... })
  for (const generator of generators) {
    if (generator.manifest?.requiresEngines) {
      generator.setBinaryPaths(binaryPathsByVersion[...])
    }
  }

  return generators
}
```

