        generatorPath: providerValue,
      }

      const generatorInstance = match(generatorDefinition)
        .with({ type: 'in-process' }, ({ generator }) => 
          new InProcessGenerator(generatorConfig, generator))
        .with({ type: 'rpc' }, ({ generatorPath, isNode }) => 
          new JsonRpcGenerator(generatorPath, generatorConfig, isNode))
        .exhaustive()

      await generatorInstance.init() // Get manifest
      generatorInstance.setOptions(options)
      return generatorInstance
    },
  )

  // 4. Check generator dependencies
  for (const g of generators) {
    if (g.manifest?.requiresGenerators) {
      for (const neededGenerator of g.manifest.requiresGenerators) {
        if (!generatorProviders.includes(neededGenerator)) {
          throw new Error(`Missing required generator: ${neededGenerator}`)
        }
      }
    }
  }

  // 5. Download binaries if needed
  const binaryPathsByVersion = await getBinaryPathsByVersion({ ... })
  for (const generator of generators) {
    if (generator.manifest?.requiresEngines) {
      generator.setBinaryPaths(binaryPathsByVersion[...])
    }
  }

  return generators
}
```

---

### 9. **SCHEMA.PRISMA GENERATOR BLOCK FORMAT**

**Location:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775491965006-gcblk5/sandbox/basic-sqlite/prisma/schema.prisma`

```prisma
generator client {
  provider = "prisma-client"
  output   = "../generated/prisma"
  # Custom config options (generator-specific)
  # For example, in prisma-client-ts:
  # runtime = "nodejs"
  # generatedFileExtension = "ts"
  # importFileExtension = "js"
}

datasource db {
  provider = "sqlite"
}

model User {
  id    String @id @default(uuid())
  email String
}
```

**Schema block semantics:**
- `provider`: Provider name (e.g., "prisma-client-js", "prisma-client") or RPC path
- `output`: Output directory for generated files (relative to schema directory)
- `binaryTargets`: (optional) Target platforms for binaries
- `previewFeatures`: (optional) Experimental features to enable
- Custom config keys: Any other key becomes available in `GeneratorConfig.config`

---

### 10. **COMPLETE END-TO-END FLOW**

```
Schema.prisma
    ↓
┌─────────────────────────────────────────┐
│ getGenerators(registry, schemaPath)     │
└─────────────────────────────────────────┘
    ↓
 Parse schema → Extract generator blocks
    ↓
 Get DMMF from engine (getDMMF)
    ↓
 For each generator block in schema:
    ├─ Look up in registry
    ├─ Create Generator instance:
    │   ├─ InProcessGenerator (for "prisma-client-js", etc.)
    │   └─ JsonRpcGenerator (for external RPC generators)
    ├─ Call init() → getManifest()
    ├─ Resolve output path
    └─ Set options
    ↓
 Check generator dependencies (requiresGenerators)
    ↓
 Download binaries for requiresEngines
    ↓
 For each generator:
    ├─ Call generate(options)
    │   ├─ (InProcess) → Direct method call
    │   └─ (JsonRpc) → Spawn child, send JSON-RPC 'generate'
    │       ├─ Child calls generatorHandler(handler)
    │       ├─ Handler calls onGenerate(options)
    │       └─ Child sends response via stderr
    └─ Collect result
    ↓
 Return generators
```

---

### 11. **KEY FILE PATHS SUMMARY**

| Component | Path |
|-----------|------|
| DMMF Types | `packages/dmmf/src/dmmf.ts` |
| Generator Interface | `packages/generator/src/generator.ts` |
| Generator Config | `packages/generator/src/configuration.ts` |
| Generator Handler | `packages/generator-helper/src/generatorHandler.ts` |
| Generator Process | `packages/generator-helper/src/GeneratorProcess.ts` |
| JSON-RPC Protocol | `packages/generator-helper/src/json-rpc.ts` |
| Generator Wrapper | `packages/internals/src/Generator.ts` |
| Generator Loader | `packages/internals/src/get-generators/getGenerators.ts` |
| PrismaClientJsGenerator | `packages/client-generator-js/src/generator.ts` |
| PrismaClientTsGenerator | `packages/client-generator-ts/src/generator.ts` |
| Generator Registry | `packages/client-generator-registry/src/registry.ts` |
| Default Registry | `packages/client-generator-registry/src/default.ts` |

---

This comprehensive guide covers:
- **DMMF structure** (Document, Model, Field, Schema, Mappings)
- **Generator interface** and how to implement it
- **JSON-RPC communication** between CLI and generators
- **Generator discovery and registration** via registry pattern
- **In-process vs. external (RPC)** generators
- **Complete execution flow** with dependency resolution and binary management

