import type { Field } from '@prisma/dmmf'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Int: 'number',
  Float: 'number',
  Boolean: 'boolean',
  DateTime: 'string',
  BigInt: 'bigint',
  Decimal: 'string',
  Bytes: 'string',
  Json: 'unknown',
}

/**
 * Maps a DMMF field's type to the corresponding TypeScript type string.
 * Returns `null` for relation (object) fields, which are omitted from REST interfaces.
 */
export function mapFieldType(field: Field): string | null {
  if (field.kind === 'object') {
    return null
  }
  if (field.kind === 'enum') {
    return field.type
  }
  if (field.kind === 'unsupported') {
    return 'unknown'
  }
  return SCALAR_TYPE_MAP[field.type] ?? 'unknown'
}

