import fs from 'node:fs/promises'
import path from 'node:path'

import type { Document } from '@prisma/dmmf'

import { generateModelCode } from './model-code-generator'

function uncapitalize(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

/**
 * Generates the REST client `index.ts` from a DMMF document and writes it to `outputDir`.
 * The output contains enum type aliases, per-model interfaces and client classes,
 * and a top-level `RestClient` that aggregates all per-model clients.
 */
export async function generateClient(dmmf: Document, outputDir: string): Promise<void> {
  const chunks: string[] = [
    '// This file was auto-generated by @prisma/rest-client-generator. Do not edit manually.',
    '',
  ]

  for (const enumDef of dmmf.datamodel.enums) {
    const values = enumDef.values.map((v) => JSON.stringify(v.name)).join(' | ')
    chunks.push(`export type ${enumDef.name} = ${values}`)
  }
  if (dmmf.datamodel.enums.length > 0) {
    chunks.push('')
  }

  for (const model of dmmf.datamodel.models) {
    chunks.push(generateModelCode(model))
    chunks.push('')
  }

  const models = dmmf.datamodel.models
  chunks.push(`export class RestClient {`)
  for (const model of models) {
    chunks.push(`  readonly ${uncapitalize(model.name)}: ${model.name}RestClient`)
  }
  chunks.push(``)
  chunks.push(`  constructor(baseUrl: string, fetchFn: typeof fetch = globalThis.fetch) {`)
  for (const model of models) {
    chunks.push(`    this.${uncapitalize(model.name)} = new ${model.name}RestClient(baseUrl, fetchFn)`)
  }
  chunks.push(`  }`)
  chunks.push(`}`)
  chunks.push(``)

  await fs.mkdir(outputDir, { recursive: true })
  await fs.writeFile(path.join(outputDir, 'index.ts'), chunks.join('\n'), 'utf-8')
}

