import { describe, expect, it } from 'vitest'

import type { Field, Model } from '@prisma/dmmf'

import { generateModelCode } from '../model-code-generator'
import { mapFieldType } from '../type-mapper'

function makeField(overrides: Partial<Field> & Pick<Field, 'name' | 'type' | 'kind'>): Field {
  return {
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  }
}

function makeModel(name: string, fields: Field[]): Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  }
}

const userModel = makeModel('User', [
  makeField({ name: 'id', type: 'Int', kind: 'scalar', isId: true, hasDefaultValue: true }),
  makeField({ name: 'name', type: 'String', kind: 'scalar' }),
  makeField({ name: 'email', type: 'String', kind: 'scalar', isRequired: false }),
  makeField({ name: 'posts', type: 'Post', kind: 'object', isList: true, isRequired: false }),
])

describe('mapFieldType', () => {
  it('maps primitive scalar types', () => {
    expect(mapFieldType(makeField({ name: 'x', type: 'String', kind: 'scalar' }))).toBe('string')
    expect(mapFieldType(makeField({ name: 'x', type: 'Int', kind: 'scalar' }))).toBe('number')
    expect(mapFieldType(makeField({ name: 'x', type: 'Float', kind: 'scalar' }))).toBe('number')
    expect(mapFieldType(makeField({ name: 'x', type: 'Boolean', kind: 'scalar' }))).toBe('boolean')
    expect(mapFieldType(makeField({ name: 'x', type: 'DateTime', kind: 'scalar' }))).toBe('string')
    expect(mapFieldType(makeField({ name: 'x', type: 'BigInt', kind: 'scalar' }))).toBe('bigint')
    expect(mapFieldType(makeField({ name: 'x', type: 'Decimal', kind: 'scalar' }))).toBe('string')
    expect(mapFieldType(makeField({ name: 'x', type: 'Bytes', kind: 'scalar' }))).toBe('string')
    expect(mapFieldType(makeField({ name: 'x', type: 'Json', kind: 'scalar' }))).toBe('unknown')
  })

  it('returns the enum type name for enum fields', () => {
    expect(mapFieldType(makeField({ name: 'role', type: 'Role', kind: 'enum' }))).toBe('Role')
  })

  it('returns null for relation (object) fields', () => {
    expect(mapFieldType(makeField({ name: 'posts', type: 'Post', kind: 'object' }))).toBeNull()
  })

  it('returns unknown for unsupported fields', () => {
    expect(mapFieldType(makeField({ name: 'x', type: 'Unsupported', kind: 'unsupported' }))).toBe('unknown')
  })
})

describe('generateModelCode', () => {
  it('generates an interface with scalar fields only, omitting relations', () => {
    const code = generateModelCode(userModel)
    expect(code).toContain('export interface User {')
    expect(code).toContain('id: number')
    expect(code).toContain('name: string')
    expect(code).toContain('email?: string')
    expect(code).not.toContain('posts')
  })

  it('generates all five argument interfaces', () => {
    const code = generateModelCode(userModel)
    expect(code).toContain('export interface UserFindManyArgs {')
    expect(code).toContain('export interface UserFindUniqueArgs {')
    expect(code).toContain('export interface UserCreateArgs {')
    expect(code).toContain('export interface UserUpdateArgs {')
    expect(code).toContain('export interface UserDeleteArgs {')
  })

  it('generates a RestClient class with all five CRUD methods', () => {
    const code = generateModelCode(userModel)
    expect(code).toContain('export class UserRestClient {')
    expect(code).toContain('async findMany(')
    expect(code).toContain('async findUnique(')
    expect(code).toContain('async create(')
    expect(code).toContain('async update(')
    expect(code).toContain('async delete(')
  })

  it('uses the lowercase model name as the REST endpoint path', () => {
    const code = generateModelCode(userModel)
    expect(code).toContain('`${this.#baseUrl}/user')
  })

  it('uses the id field type in FindUniqueArgs where clause', () => {
    const code = generateModelCode(userModel)
    expect(code).toContain('where: { id: number }')
  })

  it('marks optional interface fields with ?', () => {
    const code = generateModelCode(userModel)
    expect(code).toContain('email?: string')
    expect(code).toMatch(/\bname: string\b/)
  })

  it('generates list fields with [] suffix', () => {
    const model = makeModel('Tag', [
      makeField({ name: 'id', type: 'Int', kind: 'scalar', isId: true }),
      makeField({ name: 'values', type: 'String', kind: 'scalar', isList: true }),
    ])
    const code = generateModelCode(model)
    expect(code).toContain('values: string[]')
  })

  it('uses fetch with POST for create', () => {
    const code = generateModelCode(userModel)
    expect(code).toContain("method: 'POST'")
  })

  it('uses fetch with PATCH for update', () => {
    const code = generateModelCode(userModel)
    expect(code).toContain("method: 'PATCH'")
  })

  it('uses fetch with DELETE for delete', () => {
    const code = generateModelCode(userModel)
    expect(code).toContain("method: 'DELETE'")
  })

  it('returns null from findUnique on 404', () => {
    const code = generateModelCode(userModel)
    expect(code).toContain('if (res.status === 404) return null')
  })

  it('handles a model with an enum field', () => {
    const model = makeModel('Post', [
      makeField({ name: 'id', type: 'Int', kind: 'scalar', isId: true }),
      makeField({ name: 'status', type: 'PostStatus', kind: 'enum' }),
    ])
    const code = generateModelCode(model)
    expect(code).toContain('export interface Post {')
    expect(code).toContain('status: PostStatus')
  })

  it('falls back to Record<string, unknown> where type when no id field exists', () => {
    const model = makeModel('Setting', [
      makeField({ name: 'key', type: 'String', kind: 'scalar' }),
      makeField({ name: 'value', type: 'String', kind: 'scalar' }),
    ])
    const code = generateModelCode(model)
    expect(code).toContain('where: Record<string, unknown>')
  })
})

